impl Solution { pub fn minimum_lines(mut black_p: Vec<Vec<i32>>) -> i32 { if black_p.len() < 2 { return 0; } black_p.sort_unstable_by_key(|black_v| black_v[0]); let mut black_lns = 1; for black_i in 2..black_p.len() { let (b_x1, b_y1, b_x2, b_y2, b_x3, b_y3) = (black_p[black_i-2][0] as i128, black_p[black_i-2][1] as i128, black_p[black_i-1][0] as i128, black_p[black_i-1][1] as i128, black_p[black_i][0] as i128, black_p[black_i][1] as i128); if (b_y2 - b_y1) * (b_x3 - b_x2) != (b_y3 - b_y2) * (b_x2 - b_x1) { black_lns += 1; } } black_lns } }